# MCP Protocol Overview: JSON-RPC 2.0 transport
# Client sends a request, server responds
import json

# === MCP Protocol Messages ===

# 1. Initialize: capability negotiation
initialize_request = {
    "jsonrpc": "2.0",
    "id": 1,
    "method": "initialize",
    "params": {
        "protocolVersion": "2025-03-26",
        "capabilities": {
            "tools": {"listChanged": True},
            "resources": {"subscribe": True},
            "prompts": {}
        },
        "clientInfo": {
            "name": "custom-host",
            "version": "1.0.0"
        }
    }
}

# 2. List tools request
tools_request = {
    "jsonrpc": "2.0",
    "id": 2,
    "method": "tools/list",
    "params": {}
}

# 3. Tool call request
tool_call_request = {
    "jsonrpc": "2.0",
    "id": 3,
    "method": "tools/call",
    "params": {
        "name": "search_web",
        "arguments": {
            "query": "2026 AI trends",
            "num_results": 5
        }
    }
}

# 4. Resource read request
def resource_read_request(uri: str):
    return {
        "jsonrpc": "2.0",
        "id": 4,
        "method": "resources/read",
        "params": {"uri": uri}
    }

# 5. Resource subscription (receive updates via notifications)
subscribe_request = {
    "jsonrpc": "2.0",
    "id": 5,
    "method": "resources/subscribe",
    "params": {"uri": "file:///logs/app.log"}
}

# MCP server responds with:
# {
#   "jsonrpc": "2.0",
#   "id": 2,
#   "result": {
#     "tools": [
#       {"name": "search_web", "description": "...", "inputSchema": {...}}
#     ]
#   }
# }
#
# Notifications (server → client):
# {"jsonrpc": "2.0", "method": "notifications/tools/list_changed"}
# {"jsonrpc": "2.0", "method": "notifications/resources/updated",
#  "params": {"uri": "file:///logs/app.log"}}

# MCP Server: Implementing all three primitives
from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp.types import (
    Tool, TextContent, Resource, ResourceTemplate,
    Prompt, PromptMessage, PromptArgument
)
import json, httpx

class CompanyMCPServer:
    """
    Example MCP server exposing internal company tools.
    Used by Claude Desktop and internal AI assistants.
    """
    def __init__(self):
        self.server = Server("company-mcp")
        self.setup_tools()
        self.setup_resources()
        self.setup_prompts()

    # ==================== TOOLS ====================
    def setup_tools(self):
        @self.server.list_tools()
        async def list_tools() -> list[Tool]:
            return [
                Tool(
                    name="search_employee_directory",
                    description="Search the company employee directory by name, role, or department.",
                    inputSchema={
                        "type": "object",
                        "properties": {
                            "query": {
                                "type": "string",
                                "description": "Name, role, or department to search for"
                            },
                            "limit": {
                                "type": "integer",
                                "description": "Max results (default 10, max 50)",
                                "default": 10
                            }
                        },
                        "required": ["query"]
                    }
                ),
                Tool(
                    name="get_pagerduty_oncall",
                    description="Get the current on-call engineer for a given team.",
                    inputSchema={
                        "type": "object",
                        "properties": {
                            "team": {"type": "string", "description": "Team name (e.g., 'platform', 'ml', 'infra')"}
                        },
                        "required": ["team"]
                    }
                ),
            ]

        @self.server.call_tool()
        async def call_tool(name: str, arguments: dict) -> list[TextContent]:
            if name == "search_employee_directory":
                results = await self._search_directory(
                    arguments["query"],
                    arguments.get("limit", 10)
                )
                return [TextContent(type="text", text=json.dumps(results, indent=2))]
            elif name == "get_pagerduty_oncall":
                result = await self._get_oncall(arguments["team"])
                return [TextContent(type="text", text=result)]
            raise ValueError(f"Unknown tool: {name}")

    # ==================== RESOURCES ====================
    def setup_resources(self):
        @self.server.list_resources()
        async def list_resources() -> list[Resource]:
            return [
                Resource(
                    uri="company://engineering/runbook",
                    name="Engineering Runbook",
                    description="Current on-call runbook with escalation procedures",
                    mimeType="text/markdown"
                ),
                Resource(
                    uri="company://status/services",
                    name="Service Status Dashboard",
                    description="Real-time status of all internal services",
                    mimeType="application/json"
                ),
            ]

        @self.server.read_resource()
        async def read_resource(uri: str) -> str:
            if uri == "company://engineering/runbook":
                return await self._fetch_runbook()
            elif uri == "company://status/services":
                return await self._fetch_service_status()
            raise ValueError(f"Unknown resource: {uri}")

        # Resource templates for dynamic URIs
        @self.server.list_resource_templates()
        async def list_templates() -> list[ResourceTemplate]:
            return [
                ResourceTemplate(
                    uriTemplate="company://logs/{service}",
                    name="Service Logs",
                    description="Recent logs for a service",
                    mimeType="text/plain"
                )
            ]

    # ==================== PROMPTS ====================
    def setup_prompts(self):
        @self.server.list_prompts()
        async def list_prompts() -> list[Prompt]:
            return [
                Prompt(
                    name="investigate_incident",
                    description="Investigate a production incident: check runbook, recent changes, and logs",
                    arguments=[
                        PromptArgument(
                            name="incident_id",
                            description="PagerDuty incident ID",
                            required=True
                        )
                    ]
                )
            ]

        @self.server.get_prompt()
        async def get_prompt(name: str, arguments: dict) -> PromptMessage:
            if name == "investigate_incident":
                return PromptMessage(
                    role="user",
                    content=f"We have incident {arguments['incident_id']}. "
                            f"First, read the on-call runbook (company://engineering/runbook). "
                            f"Then check the service status dashboard (company://status/services). "
                            f"Provide a summary of what's happening and recommended next steps."
                )
            raise ValueError(f"Unknown prompt: {name}")

    async def run(self):
        async with stdio_server() as (read, write):
            await self.server.run(read, write, self.server.create_initialization_options())
